interface.pattern:
@Service
class TenantQuotaManager(
  private val tenantContext: TenantContext,
  private val quotaConfig: TenantQuotaConfiguration,
  private val meterRegistry: MeterRegistry
) {
  private val buckets = ConcurrentHashMap<String, Bucket>()

  fun checkEventQuota(): Boolean {
    val tenantId = tenantContext.getCurrentTenantId()
    val bucket = getBucketForTenant(tenantId)
    val consumed = bucket.tryConsume(1)

    if (!consumed) {
      meterRegistry.counter("tenant_quota_rejected_total", "tenant_id", tenantId).increment()
    }

    return consumed
  }

  private fun getBucketForTenant(tenantId: String): Bucket {
    return buckets.computeIfAbsent(tenantId) { createBucket(tenantId) }
  }

  private fun createBucket(tenantId: String): Bucket {
    val limit = quotaConfig.getEventLimit(tenantId)
    return Bucket.builder()
      .addLimit(Bandwidth.simple(limit, Duration.ofSeconds(1)))
      .build()
  }
}

@Component
class QuotaEnforcementInterceptor(
  private val quotaManager: TenantQuotaManager
) : MessageHandlerInterceptor<CommandMessage<*>> {

  override fun handle(unitOfWork: UnitOfWork<out CommandMessage<*>>, chain: InterceptorChain): Any? {
    if (!quotaManager.checkEventQuota()) {
      throw ResponseStatusException(
        HttpStatus.TOO_MANY_REQUESTS,
        "Quota exceeded"
      ).also {
        it.setHeader("Retry-After", quotaManager.getRetryAfterSeconds().toString())
      }
    }
    return chain.proceed()
  }
}

@Configuration
class TenantQuotaConfiguration(
  private val quotaRepository: TenantQuotaRepository
) {
  fun getEventLimit(tenantId: String): Long {
    return quotaRepository.findByTenantId(tenantId)
      ?.maxEventsPerSecond
      ?: defaultEventLimit
  }

  companion object {
    const val defaultEventLimit = 100L // Default: 100 events/second
    const val defaultStorageLimitMb = 1000L // Default: 1GB storage
  }
}
